import type { DrawResult } from '../types/draw-result.js';
import type { FreshnessView } from '../diagnostics/types.js';

export const DEFAULT_STALE_DRAW_MS = 10 * 60_000;

export function formatAgeLabel(ageMs: number): string {
  const seconds = Math.max(0, Math.round(ageMs / 1000));
  if (seconds < 60) {
    return `${String(seconds)}s`;
  }
  const minutes = Math.round(seconds / 60);
  if (minutes < 60) {
    return `${String(minutes * 60)}s`;
  }
  return `${String(Math.round(seconds))}s`;
}

export function buildFreshnessView(
  latestDraw: DrawResult | null,
  now: number,
  staleThresholdMs = DEFAULT_STALE_DRAW_MS,
): FreshnessView {
  if (latestDraw === null) {
    return {
      lastDrawAgeMs: null,
      lastDrawAgeLabel: 'n/a',
      stale: true,
      warning: 'No draw stored',
    };
  }

  const anchor = latestDraw.collectedAt ?? latestDraw.drawAt;
  const lastDrawAgeMs = now - new Date(anchor).getTime();
  const stale = lastDrawAgeMs >= staleThresholdMs;
  const label = formatAgeLabel(lastDrawAgeMs);

  return {
    lastDrawAgeMs,
    lastDrawAgeLabel: label,
    stale,
    warning: stale ? `Last draw older than ${String(Math.round(staleThresholdMs / 1000))}s` : null,
  };
}

export {
  CollectorRequestError,
  classifyFetchError,
  type RetryErrorType,
} from './retry-errors.js';
export {
  DEFAULT_RETRY_POLICY,
  executeWithRetry,
  retryDelayMs,
  withRetry,
  type RetryPolicyOptions,
} from './retry-policy.js';
export {
  loadRetryObservabilitySnapshot,
  recordRetryAttempt,
  recordRetryExhausted,
  recordRetrySuccess,
  resetRetryObservabilityForTests,
  type RetryObservabilitySnapshot,
} from './retry-state.js';

import { mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname } from 'node:path';

import type { RetryErrorType } from './retry-errors.js';

export interface RetryObservabilitySnapshot {
  readonly retryCount: number;
  readonly lastRetryAt: string | null;
  readonly lastErrorType: RetryErrorType | null;
  readonly lastSuccessAt: string | null;
}

const EMPTY_SNAPSHOT: RetryObservabilitySnapshot = {
  retryCount: 0,
  lastRetryAt: null,
  lastErrorType: null,
  lastSuccessAt: null,
};

function statePath(): string {
  return process.env['COLLECTOR_RETRY_STATE_PATH'] ?? './data/retry-state.json';
}

function readSnapshot(): RetryObservabilitySnapshot {
  try {
    const raw = readFileSync(statePath(), 'utf8');
    const parsed = JSON.parse(raw) as Partial<RetryObservabilitySnapshot>;
    return {
      retryCount: typeof parsed.retryCount === 'number' ? parsed.retryCount : 0,
      lastRetryAt: typeof parsed.lastRetryAt === 'string' ? parsed.lastRetryAt : null,
      lastErrorType:
        typeof parsed.lastErrorType === 'string' ? (parsed.lastErrorType as RetryErrorType) : null,
      lastSuccessAt: typeof parsed.lastSuccessAt === 'string' ? parsed.lastSuccessAt : null,
    };
  } catch {
    return EMPTY_SNAPSHOT;
  }
}

function writeSnapshot(snapshot: RetryObservabilitySnapshot): void {
  const path = statePath();
  mkdirSync(dirname(path), { recursive: true });
  writeFileSync(path, `${JSON.stringify(snapshot, null, 2)}\n`, 'utf8');
}

export function loadRetryObservabilitySnapshot(): RetryObservabilitySnapshot {
  return readSnapshot();
}

export function resetRetryObservabilityForTests(): void {
  writeSnapshot(EMPTY_SNAPSHOT);
}

export function recordRetryAttempt(errorType: RetryErrorType): void {
  const current = readSnapshot();
  writeSnapshot({
    retryCount: current.retryCount + 1,
    lastRetryAt: new Date().toISOString(),
    lastErrorType: errorType,
    lastSuccessAt: current.lastSuccessAt,
  });
}

export function recordRetrySuccess(): void {
  const current = readSnapshot();
  writeSnapshot({
    ...current,
    lastSuccessAt: new Date().toISOString(),
    lastErrorType: null,
  });
}

export function recordRetryExhausted(errorType: RetryErrorType): void {
  const current = readSnapshot();
  writeSnapshot({
    ...current,
    lastErrorType: errorType,
  });
}

import { executeWithRetry, type RetryPolicyOptions as PolicyOptions } from '../retry/retry-policy.js';

export interface RetryOptions {
  readonly maxAttempts?: number;
  readonly baseDelayMs?: number;
  readonly label?: string;
}

export async function withRetry<T>(fn: () => Promise<T>, options: RetryOptions = {}): Promise<T> {
  return executeWithRetry(fn, options as PolicyOptions);
}

export function isSqliteBusyError(err: unknown): boolean {
  if (typeof err !== 'object' || err === null) return false;
  const code = (err as { code?: string }).code;
  return code === 'SQLITE_BUSY' || code === 'SQLITE_LOCKED';
}

export async function withSqliteRetry<T>(fn: () => T | Promise<T>, maxAttempts = 5): Promise<T> {
  let lastError: unknown;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;
      if (!isSqliteBusyError(err) || attempt === maxAttempts) throw err;
      await new Promise((resolve) => setTimeout(resolve, 50 * attempt));
    }
  }

  throw lastError;
}

