  createDiagnosticCapabilities,
  DiagnosticsPage,
  DiagnosticsProvider,
  type BuildStatusSnapshot,
  type CloudStatusSnapshot,
  type CollectorStatusSnapshot,
  type SessionStatusSnapshot,
  type StatusTone,
} from '@/product-shell/ui';
import type { CollectorHealthResponse } from '@/features/game-monitor/collector-api-types';
import { getCollectorApiBase } from '@/features/game-monitor/collector-endpoint';

interface ToastState {
  readonly message: string;
  readonly actionLabel?: string;
  readonly onAction?: () => void;
}

function findSession(sessions: readonly Session[], id: string | null): Session | null {
  if (id === null) {
    return null;
  }
  return sessions.find((s) => s.id === id) ?? null;
}

export function App(): JSX.Element {
  return (
    <AppServicesProvider>
      <AppRoot />
    </AppServicesProvider>
  );
}

function AppRoot(): JSX.Element {
  const services = useServices();
  const planningDraftRepository = useMemo(
    () => new PlanningDraftRepository(services.storage),
    [services.storage],
  );
  const sessionRepository = useMemo(
    () => new SessionRepository(services.storage),
    [services.storage],
  );
  const libraryRepository = useMemo(
    () => new LibraryRepository(services.storage),
    [services.storage],
  );
  const planCandidateRepository = useMemo(
    () => new PlanCandidateRepository(services.storage),
    [services.storage],
  );
  const deletePlanCandidateUseCase = useMemo(
    () => createDeletePlanCandidateUseCase({ candidates: planCandidateRepository }),
    [planCandidateRepository],
  );
  const recommendationSetRepository = useMemo(
    () => new RecommendationSetRepository(services.storage),
    [services.storage],
  );
  const generatePlanUseCase = useMemo(
    () =>
      createGeneratePlanUseCase({
        planningDrafts: planningDraftRepository,
        events: services.events,
        clock: services.clock,
      }),
    [planningDraftRepository, services.events, services.clock],
  );
  const promotePlanningDraftUseCase = useMemo(
    () =>
      createPromotePlanningDraftUseCase({
        planningDrafts: planningDraftRepository,
        sessions: sessionRepository,
        events: services.events,
        clock: services.clock,
      }),
    [planningDraftRepository, sessionRepository, services.events, services.clock],
  );
  const createImprovementCandidate = useMemo(
    () =>
      createImprovementCandidateUseCase({
        candidates: planCandidateRepository,
        sessions: sessionRepository,
        events: services.events,
        clock: services.clock,
      }),
    [planCandidateRepository, sessionRepository, services.events, services.clock],
  );
  const promoteCandidateToPlan = useMemo(
    () =>
      createPromoteCandidateToPlanUseCase({
        candidates: planCandidateRepository,
        sessions: sessionRepository,
        events: services.events,
        clock: services.clock,
      }),
    [planCandidateRepository, sessionRepository, services.events, services.clock],
  );
  const generateCapitalRecommendations = useMemo(
    () =>
      createGenerateCapitalRecommendationsUseCase({
        recommendationSets: recommendationSetRepository,
        candidates: planCandidateRepository,
        events: services.events,
        clock: services.clock,
      }),
    [recommendationSetRepository, planCandidateRepository, services.events, services.clock],
  );
  const createCandidateFromRecommendation = useMemo(
    () =>
      createCandidateFromRecommendationUseCase({
        recommendationSets: recommendationSetRepository,
        candidates: planCandidateRepository,
        events: services.events,
        clock: services.clock,
      }),
    [recommendationSetRepository, planCandidateRepository, services.events, services.clock],
  );
  const promoteCandidateToSession = useMemo(
    () =>
      createPromoteCandidateToSessionUseCase({
        candidates: planCandidateRepository,
        sessions: sessionRepository,
        events: services.events,
        clock: services.clock,
      }),
    [planCandidateRepository, sessionRepository, services.events, services.clock],
  );
  const continuePlanUseCase = useMemo(
    () =>
      createContinuePlanUseCase({
        sessions: sessionRepository,
        events: services.events,
        clock: services.clock,
      }),
    [sessionRepository, services.events, services.clock],
  );
  const startPlanUseCase = useMemo(
    () => createStartPlanUseCase({ sessions: sessionRepository }),
    [sessionRepository],
  );
  const stopSessionUseCase = useMemo(
    () => createStopSessionUseCase({ sessions: sessionRepository }),
    [sessionRepository],
  );
  const savePlayingSessionUseCase = useMemo(
    () => createSavePlayingSessionUseCase({ sessions: sessionRepository }),
    [sessionRepository],
  );
  const winSessionUseCase = useMemo(
    () => createWinSessionUseCase({ sessions: sessionRepository }),
    [sessionRepository],
  );
  const updateSessionUseCase = useMemo(
    () => createUpdateSessionUseCase({ sessions: sessionRepository }),
    [sessionRepository],
  );
  const duplicateLibrarySessionUseCase = useMemo(
    () => createDuplicateLibrarySessionUseCase({ sessions: sessionRepository }),
    [sessionRepository],
  );
  const addLibraryCollectionUseCase = useMemo(
    () => createAddLibraryCollectionUseCase({ library: libraryRepository }),
    [libraryRepository],
  );
  const generateExperimentRecommendations = useMemo(
    () =>
      createGenerateExperimentRecommendationsUseCase({
        recommendationSets: recommendationSetRepository,
        candidates: planCandidateRepository,
        events: services.events,
        clock: services.clock,
      }),
    [recommendationSetRepository, planCandidateRepository, services.events, services.clock],
  );

  const [hydrated, setHydrated] = useState(false);
  const [persisted, setPersisted] = useState<PersistedAppState>(EMPTY_PERSISTED_STATE);
  const [activeWorkspace, setActiveWorkspace] = useState<WorkspaceId>('dashboard');
  const [sessionView, setSessionView] = useState<SessionView>('overview');
  const [viewingSessionId, setViewingSessionId] = useState<string | null>(null);
  const [liveForm, setLiveForm] = useState<PlannerFormValues>(DEFAULT_PLANNER_FORM);
  const [fieldErrors, setFieldErrors] = useState<Partial<Record<PlannerField, string>>>({});
  const [planningView, setPlanningView] = useState<PlanningView>('form');
  const [capitalReviewOpen, setCapitalReviewOpen] = useState(false);
  const [scenarioReviewOpen, setScenarioReviewOpen] = useState(false);
  const [toast, setToast] = useState<ToastState | null>(null);
  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const activeSession = findSession(persisted.sessions, persisted.activeSessionId);
  const displayedSession = findSession(persisted.sessions, viewingSessionId) ?? activeSession;
  const allPresets = useMemo(
    () => mergePresets(persisted.customGamePresets),
    [persisted.customGamePresets],
  );
  const activePreset = findPreset(allPresets, persisted.activePresetId);
  const statisticsPreset =
    activeSession !== null ? findPreset(allPresets, activeSession.presetId) : activePreset;
  const {
    snapshot: gameStatistics,
    draws: gameDraws,
    loading: gameStatisticsLoading,
    error: gameStatisticsError,
    refresh: refreshGameStatistics,
  } = useGameStatistics(statisticsPreset);
  const continuePolicy =
    activePreset !== undefined
      ? activePreset.continuePolicy
      : { maximumRounds: 5000, presets: [1000, 1500, 2000, 5000] };
  const currentPlan = activeSession !== null ? getCurrentPlan(activeSession) : null;
  const capitalOverview = useMemo(() => computeCapitalOverview(persisted), [persisted]);
  const readOnlySession =
    viewingSessionId !== null && viewingSessionId !== persisted.activeSessionId;

  useEffect(() => {
    void services.storage.load().then((state) => {
      setPersisted(state);
      const presets = mergePresets(state.customGamePresets);
      const preset = findPreset(presets, state.activePresetId);
      const base = DEFAULT_PLANNER_FORM;
      setLiveForm(preset !== undefined ? applyPresetToForm(base, preset) : base);
      const hasActive = state.activeSessionId !== null;
      const restoredSession = findSession(state.sessions, state.activeSessionId);
      if (state.planCandidate !== null && isNewSessionCandidate(state.planCandidate)) {
        setActiveWorkspace('capital');
        setCapitalReviewOpen(true);
      } else {
        setActiveWorkspace(hasActive ? 'session' : 'dashboard');
        setCapitalReviewOpen(false);
      }
      if (
        state.planCandidate !== null &&
        state.planCandidate.target === 'append-plan' &&
        state.activeSessionId === state.planCandidate.sessionId
      ) {
        setSessionView('improve-review');
      } else {
        setSessionView(restoredSession?.status === 'playing' ? 'playing' : 'overview');
      }
      setPlanningView(state.planningDraft !== null ? 'decision' : 'form');
      setHydrated(true);
    });
  }, [services.storage]);

  const persist = useCallback((next: PersistedAppState) => {
    setPersisted(next);
    if (saveTimer.current !== null) {
      clearTimeout(saveTimer.current);
    }
    saveTimer.current = setTimeout(() => {
      void services.storage.save(next);
    }, 250);
  }, [services.storage]);

  const applyPersistedState = useCallback((next: PersistedAppState) => {
    setPersisted(next);
  }, []);

  const runLibrarySessionMutation = useCallback(
    (sessionId: string, updater: (session: Session) => Session) => {
      void updateSessionUseCase.execute(sessionId, updater).then((next) => {
        if (next !== null) {
          applyPersistedState(next);
        }
      });
    },
    [applyPersistedState, updateSessionUseCase],
  );

  useEffect(() => {
    document.querySelector('main')?.scrollTo({ top: 0, behavior: 'instant' });
  }, [activeWorkspace, sessionView]);

  const showToastRef = useRef<(message: string) => void>(() => {});

  function showToast(message: string, actionLabel?: string, onAction?: () => void): void {
    setToast({
      message,
      ...(actionLabel !== undefined ? { actionLabel } : {}),
      ...(onAction !== undefined ? { onAction } : {}),
    });
    setTimeout(() => {
      setToast(null);
    }, 4000);
  }
  showToastRef.current = (message: string) => {
    showToast(message);
  };

  const shellRuntime = useMemo(() => createShellRuntime(), []);

  const shellAppContext = useMemo(
    () =>
      createAppContext({
        navigate: (workspaceId) => {
          if (workspaceId !== 'session') {
            setViewingSessionId(null);
          }
          setActiveWorkspace(workspaceId);
        },
        notifications: {
          notify: (message) => {
            showToastRef.current(message);
          },
        },
        flags: {
          onPlanningWorkspace: activeWorkspace === 'planning',
          planReady: planningView === 'plan',
          cloud: services.flags.isEnabled('cloud'),
        },
        services: {},
      }),
    [activeWorkspace, planningView, services.flags],
  );

  const collectorStatusSnapshot = useMemo((): CollectorStatusSnapshot => {
    let tone: StatusTone = 'ok';
    let label = 'Collector 🟢';
    if (gameStatisticsError) {
      tone = 'error';
      label = 'Collector 🔴';
    } else if (gameStatisticsLoading) {
      tone = 'warning';
      label = 'Collector 🟡';
    }
    return {
      id: 'collector',
      label,
      tone,
      onClick: () => {
        setActiveWorkspace('game-monitor');
      },
    };
  }, [gameStatisticsError, gameStatisticsLoading]);

  const sessionStatusSnapshot = useMemo((): SessionStatusSnapshot => {
    const openSession = () => {
      setActiveWorkspace('session');
    };
    if (activeSession === null) {
      return {
        id: 'session',
        label: '—',
        tone: 'neutral',
        onClick: openSession,
      };
    }
    const plan = getCurrentPlan(activeSession);
    const totalRounds = plan?.generated.strategy.rounds.length;
    const roundsLeft =
      plan !== null && totalRounds !== undefined
        ? Math.max(0, totalRounds - plan.completedThroughRound)
        : undefined;
    const statusLabel =
      activeSession.status === 'playing'
        ? 'Playing'
        : activeSession.status === 'draft'
          ? 'Draft'
          : activeSession.status;
    return {
      id: 'session',
      label: statusLabel,
      ...(roundsLeft !== undefined ? { detail: `${roundsLeft} rounds left` } : {}),
      tone: activeSession.status === 'playing' ? 'ok' : 'neutral',
      onClick: openSession,
    };
  }, [activeSession]);

  const cloudStatusSnapshot = useMemo((): CloudStatusSnapshot => {
    const cloudEnabled = services.flags.isEnabled('cloud');
    return {
      id: 'cloud',
      label: cloudEnabled ? 'Cloud ON' : 'Cloud OFF',
      tone: cloudEnabled ? 'ok' : 'disabled',
      onClick: () => {
        setActiveWorkspace('settings');
      },
    };
  }, [services.flags]);

  const buildStatusSnapshot = useMemo((): BuildStatusSnapshot => {
    return {
      id: 'build',
      label: `v${services.config.build.buildVersion}`,
      tone: 'neutral',
      onClick: () => {
        setActiveWorkspace('settings');
      },
    };
  }, [services.config.build.buildVersion]);

  const notificationState: NotificationState = useMemo(
    () => ({
      notifications: persisted.notifications,
      preferences: persisted.notificationPreferences,
    }),
    [persisted.notifications, persisted.notificationPreferences],
  );

  const handleNotificationStateChange = useCallback((next: NotificationState) => {
    setPersisted((prev) => {
      const updated: PersistedAppState = {
        ...prev,
        notifications: next.notifications,
        notificationPreferences: next.preferences,
      };
      void services.storage.save(updated);
      return updated;
    });
  }, [services.storage]);

  const {
    unreadCount: notificationUnreadCount,
    ingestSettlementAlerts,
    markRead: markNotificationRead,
    markAllRead: markAllNotificationsRead,
    clearAll: clearAllNotifications,
    updatePreferences: updateNotificationPreferences,
  } = useNotificationCenter({
    state: notificationState,
    onStateChange: handleNotificationStateChange,
    onToast: (message) => {
      showToastRef.current(message);
    },
  });

  const diagnosticCapabilities = useMemo(
    () =>
      createDiagnosticCapabilities(
        createAppDiagnosticsPorts({
          fetchCollectorHealth: async (): Promise<CollectorHealthResponse | null> => {
            try {
              const response = await fetch(`${getCollectorApiBase()}/health`, {
                headers: { Accept: 'application/json' },
              });
              if (!response.ok) {
                return null;
              }
              return (await response.json()) as CollectorHealthResponse;
            } catch {
              return null;
            }
          },
          notificationCount: persisted.notifications.length,
          unreadNotificationCount: notificationUnreadCount,
          statisticsError: gameStatisticsError,
          statisticsLoading: gameStatisticsLoading,
          statisticsDrawCount: gameDraws.length > 0 ? gameDraws.length : null,
          cloudEnabled: services.flags.isEnabled('cloud'),
          buildVersion: services.config.build.buildVersion,
          runtimeHealthy: services.health.getSnapshot().status === 'ok',
        }),
      ),
    [
      gameDraws.length,
      gameStatisticsError,
      gameStatisticsLoading,
      notificationUnreadCount,
      persisted.notifications.length,
      services.config.build.buildVersion,
      services.flags,
      services.health,
    ],
  );

  const activeSessionRef = useRef(activeSession);
  activeSessionRef.current = activeSession;

  const ingestSettlementAlertsRef = useRef(ingestSettlementAlerts);
  ingestSettlementAlertsRef.current = ingestSettlementAlerts;

  const settlementCallbacks = useMemo(
    () => ({
      onSessionUpdate: (session: Session) => {
        void savePlayingSessionUseCase.execute(session).then(applyPersistedState);
      },
      onAlerts: (alerts: readonly SettlementAlert[]) => {
        const session = activeSessionRef.current;
        const plan = session !== null ? getCurrentPlan(session) : null;
        if (session !== null && plan !== null) {
          ingestSettlementAlertsRef.current(alerts, {
            sessionId: session.id,
            planLabel: plan.label,
          });
        }
      },
      onWin: (session: Session) => {
        void winSessionUseCase.execute(session).then((next) => {
          applyPersistedState(next);
          setSessionView('overview');
          setActiveWorkspace('session');
        });
      },
    }),
    [applyPersistedState, savePlayingSessionUseCase, winSessionUseCase],
  );

  const latestDraw = useAutoSettlement(
    persisted.activeSessionId !== null && activeSession?.status === 'playing'
      ? activeSession
      : null,
    activeSession !== null ? findPreset(allPresets, activeSession.presetId) : undefined,
    settlementCallbacks,
  );

  async function handlePromoteDraft(startPlaying: boolean): Promise<void> {
    const result = await promotePlanningDraftUseCase.execute({ startPlaying });
    if (!result.ok) {
      showToast('Không có bản nháp kế hoạch');
      return;
    }

    applyPersistedState(result.nextState);
    setPlanningView('form');
    setViewingSessionId(null);
    setSessionView(startPlaying ? 'playing' : 'overview');
    setActiveWorkspace('session');
    showToast(startPlaying ? 'Bắt đầu chơi' : 'Session đã tạo từ kế hoạch');
  }

  async function handlePlanningGenerate(values: PlannerFormValues): Promise<void> {
    const result = await generatePlanUseCase.execute({
      formValues: values,
      presetId: persisted.activePresetId,
    });
    if (!result.ok) {
      setFieldErrors(result.fieldErrors);
      return;
    }
    setFieldErrors({});
    applyPersistedState(result.nextState);
    setPlanningView('decision');
  }

  function renderPlanningWorkspace(): JSX.Element {
    const draft = persisted.planningDraft;
    if (planningView === 'decision' && draft !== null) {
      return (
        <DecisionScreen
          generated={draft.generated}
          onEdit={() => {
            setPlanningView('form');
          }}
          onViewPlan={() => {
            setPlanningView('plan');
          }}
          onStartPlaying={() => {
            void handlePromoteDraft(true);
          }}
        />
      );
    }
    if (planningView === 'plan' && draft !== null) {
      return (
        <div className="space-y-4">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => {
              setPlanningView('decision');
            }}
          >
            ← Kết quả
          </Button>
          <PlanTableScreen
            generated={draft.generated}
            completedThroughRound={0}
            onToggleRound={() => undefined}
            onResetProgress={() => undefined}
            onEdit={() => {
              setPlanningView('form');
            }}
            hideContinue
          />
          <Button size="lg" onClick={() => void handlePromoteDraft(true)}>
            Bắt đầu chơi
          </Button>
        </div>
      );
    }
    return (
      <GeneratePlanScreen
        key={persisted.activePresetId}
        defaultValues={liveForm}
        presets={allPresets}
        activePresetId={persisted.activePresetId}
        onPresetSelect={handlePresetSelect}
        onValuesChange={setLiveForm}
        onSubmit={(values) => {
          void handlePlanningGenerate(values);
        }}
        {...(fieldErrors.request !== undefined ? { serverError: fieldErrors.request } : {})}
      />
    );
  }

  function handlePresetSelect(preset: GamePolicyPreset): void {
    const next = applyPresetToForm(liveForm, preset);
    setLiveForm(next);
    persist({ ...persisted, activePresetId: preset.id });
  }

  function handleSaveGamePreset(preset: GamePolicyPreset): void {
    const without = persisted.customGamePresets.filter((p) => p.id !== preset.id);
    persist({
      ...persisted,
      customGamePresets: [...without, preset],
      activePresetId: preset.id,
    });
    showToast(`Đã lưu preset "${preset.name}"`);
  }

  function handleDeleteGamePreset(id: string): void {
    const filtered = persisted.customGamePresets.filter((p) => p.id !== id);
    const nextPresetId =
      persisted.activePresetId === id ? DEFAULT_PRESET_ID : persisted.activePresetId;
    persist({
      ...persisted,
      customGamePresets: filtered,
      activePresetId: nextPresetId,
    });
    showToast('Đã xóa preset');
  }

  function startPlan(): void {
    if (persisted.activeSessionId === null) {
      return;
    }
    void startPlanUseCase.execute(persisted.activeSessionId).then((result) => {
      if (result.ok) {
        applyPersistedState(result.nextState);
      }
    });
  }

  async function handleContinue(targetRoundCount: number): Promise<void> {
    if (persisted.activeSessionId === null) {
      return;
    }
    const result = await continuePlanUseCase.execute({
      sessionId: persisted.activeSessionId,
      targetTotalRounds: targetRoundCount,
    });
    if (!result.ok) {
      showToast(result.message ?? 'Không tiếp tục được session');
      return;
    }
    applyPersistedState(result.nextState);
    showToast(`Plan mới đến ${String(targetRoundCount)} vòng`);
    setSessionView('playing');
  }

  async function handleSelectImproveOption(option: ImproveOption): Promise<void> {
    if (persisted.activeSessionId === null) {
      return;
    }
    const result = await createImprovementCandidate.execute({
      sessionId: persisted.activeSessionId,
      option,
    });
    if (!result.ok) {
      showToast('Không tạo được phương án cải thiện');
      return;
    }
    applyPersistedState(result.nextState);
    setSessionView('improve-review');
  }

  async function handlePromoteCandidate(): Promise<void> {
    const candidate = persisted.planCandidate;
    if (candidate !== null && isNewSessionCandidate(candidate)) {
      await handlePromoteNewSessionCandidate();
      return;
    }

    const result = await promoteCandidateToPlan.execute();
    if (!result.ok) {
      showToast('Không có phương án để thêm');
      return;
    }
    applyPersistedState(result.nextState);
    setSessionView(result.session.status === 'playing' ? 'playing' : 'overview');
    showToast('Plan mới đã được thêm vào session');
  }

  async function handleDiscardCandidate(): Promise<void> {
    const candidate = persisted.planCandidate;
    const isCapital =
      candidate !== null && isNewSessionCandidate(candidate) && candidate.source === 'capital';
    const isScenario =
      candidate !== null && isNewSessionCandidate(candidate) && candidate.source === 'scenario';
    const result = await deletePlanCandidateUseCase.execute();
    if (!result.ok) {
      return;
    }
    applyPersistedState(result.nextState);
    if (isCapital) {
      setCapitalReviewOpen(false);
      setActiveWorkspace('capital');
    } else if (isScenario) {
      setScenarioReviewOpen(false);
      setActiveWorkspace('scenario');
    } else {
      setSessionView('improve');
    }
    showToast('Đã hủy phương án');
  }

  async function handleUseCapitalRecommendation(recommendationId: string): Promise<void> {
    const result = await createCandidateFromRecommendation.execute({ recommendationId });
    if (!result.ok) {
      showToast('Không chọn được phương án');
      return;
    }
    applyPersistedState(result.nextState);
    setCapitalReviewOpen(true);
  }

  async function handleGenerateCapital(input: CapitalPlannerInput) {
    const generated = await generateCapitalRecommendations.execute(input);
    if (!generated.ok) {
      return null;
    }
    setCapitalReviewOpen(false);
    applyPersistedState(generated.nextState);
    return generated.recommendationSet;
  }

  async function handlePromoteNewSessionCandidate(): Promise<void> {
    const label = persisted.planCandidate?.label ?? 'Session mới';
    const result = await promoteCandidateToSession.execute({ stopActivePlaying: true });
    if (!result.ok) {
      showToast('Không tạo được session');
      return;
    }

    applyPersistedState(result.nextState);
    setCapitalReviewOpen(false);
    setScenarioReviewOpen(false);
    setViewingSessionId(null);
    setSessionView('overview');
    setActiveWorkspace('session');
    showToast(`Session từ ${label} — Plan A sẵn sàng`);
  }

  async function handleUseExperiment(
    selected: Experiment,
    allExperiments: readonly Experiment[],
  ): Promise<void> {
    const generated = await generateExperimentRecommendations.execute({
      experiments: allExperiments,
      presetId: persisted.activePresetId,
    });
    if (!generated.ok) {
      showToast('Không có experiment hợp lệ để tạo khuyến nghị');
      return;
    }

    const result = await createCandidateFromRecommendation.execute({
      recommendationId: selected.id,
    });
    if (!result.ok) {
      showToast('Không chọn được experiment');
      return;
    }

    applyPersistedState(result.nextState);
    setScenarioReviewOpen(true);
  }

  function handleNotesChange(notes: string): void {
    const id = viewingSessionId ?? persisted.activeSessionId;
    if (id === null) {
      return;
    }
    void updateSessionUseCase.execute(id, (s) => updateSessionNotes(s, notes)).then((next) => {
      if (next !== null) {
        applyPersistedState(next);
      }
    });
  }

  function handleTitleChange(title: string): void {
    const id = viewingSessionId ?? persisted.activeSessionId;
    if (id === null) {
      return;
    }
    void updateSessionUseCase.execute(id, (s) => updateSessionTitle(s, title)).then((next) => {
      if (next !== null) {
        applyPersistedState(next);
      }
    });
  }

  function renderCapitalWorkspace(): JSX.Element {
    const capitalCandidate =
      persisted.planCandidate !== null &&
      isNewSessionCandidate(persisted.planCandidate) &&
      persisted.planCandidate.source === 'capital'
        ? persisted.planCandidate
        : null;

    if (capitalCandidate !== null && capitalReviewOpen) {
      const capitalPreset = findPreset(allPresets, capitalCandidate.presetId);
      return (
        <ImproveCandidateReviewScreen
          candidate={capitalCandidate}
          {...(capitalPreset !== undefined ? { preset: capitalPreset } : {})}
          onBack={() => {
            setCapitalReviewOpen(false);
          }}
          onPromote={() => void handlePromoteNewSessionCandidate()}
          onDiscard={() => void handleDiscardCandidate()}
          promoteLabel="Bắt đầu session"
          backLabel="Quay lại khuyến nghị"
          subtitle={`${capitalCandidate.label} — xác nhận trước khi tạo session`}
        />
      );
    }

    const savedMarketId =
      persisted.recommendationSet?.marketId ?? persisted.capitalPlanner?.marketId;

    return (
      <div className="space-y-4">
        {capitalCandidate !== null ? (
          <div className="flex flex-wrap items-center justify-between gap-2 rounded-lg border border-primary/30 bg-primary/5 px-4 py-3 text-sm">
            <span>Phương án Capital đang chờ xác nhận</span>
            <Button
              size="sm"
              variant="outline"
              onClick={() => {
                setCapitalReviewOpen(true);
              }}
            >
              Xem lại phương án
            </Button>
          </div>
        ) : null}
        <CapitalPlannerScreen
          presets={allPresets}
          activePresetId={persisted.activePresetId}
          initialBankroll={
            (
              persisted.recommendationSet?.totalBankroll ?? persisted.capitalPlanner?.totalBankroll
            )?.toLocaleString('vi-VN') ?? liveForm.userBankroll
          }
          initialStrategy={
            persisted.recommendationSet?.strategy ??
            persisted.capitalPlanner?.strategy ??
            'balanced'
          }
          initialRisk={
            persisted.recommendationSet?.risk ?? persisted.capitalPlanner?.risk ?? 'normal'
          }
          {...(savedMarketId !== undefined ? { initialMarketId: savedMarketId } : {})}
          recommendationSet={persisted.recommendationSet}
          onPresetSelect={handlePresetSelect}
          onGenerate={handleGenerateCapital}
          onUseRecommendation={(id) => void handleUseCapitalRecommendation(id)}
        />
      </div>
    );
  }

  function renderScenarioWorkspace(): JSX.Element {
    const scenarioCandidate =
      persisted.planCandidate !== null &&
      isNewSessionCandidate(persisted.planCandidate) &&
      persisted.planCandidate.source === 'scenario'
        ? persisted.planCandidate
        : null;

    if (scenarioCandidate !== null && scenarioReviewOpen) {
      const scenarioPreset = findPreset(allPresets, scenarioCandidate.presetId);
      return (
        <ImproveCandidateReviewScreen
          candidate={scenarioCandidate}
          {...(scenarioPreset !== undefined ? { preset: scenarioPreset } : {})}
          onBack={() => {
            setScenarioReviewOpen(false);
          }}
          onPromote={() => void handlePromoteNewSessionCandidate()}
          onDiscard={() => void handleDiscardCandidate()}
          promoteLabel="Bắt đầu session"
          backLabel="Quay lại Scenario Planner"
          subtitle={`${scenarioCandidate.label} — xác nhận trước khi tạo session`}
        />
      );
    }

    return (
      <div className="space-y-4">
        {scenarioCandidate !== null ? (
          <div className="flex flex-wrap items-center justify-between gap-2 rounded-lg border border-primary/30 bg-primary/5 px-4 py-3 text-sm">
            <span>Experiment đang chờ xác nhận</span>
            <Button
              size="sm"
              variant="outline"
              onClick={() => {
                setScenarioReviewOpen(true);
              }}
            >
              Xem lại phương án
            </Button>
          </div>
        ) : null}
        <ScenarioPlannerScreen
          presets={allPresets}
          activePresetId={persisted.activePresetId}
          onPresetSelect={handlePresetSelect}
          onUseExperiment={(experiment, all) => void handleUseExperiment(experiment, all)}
          onPromotePreset={handleSaveGamePreset}
        />
      </div>
    );
  }

  function handleStopSession(): void {
    void stopSessionUseCase.execute().then((result) => {
      if (!result.ok) {
        return;
      }
      applyPersistedState(result.nextState);
      showToast('Session đã dừng — xem trong Library');
      setViewingSessionId(null);
    });
  }

  function handleExportSession(): void {
    if (displayedSession === null) {
      return;
    }
    exportFullSessionJson(displayedSession);
    showToast('Đã xuất session JSON');
  }

  function renderSessionWorkspace(): JSX.Element {
    if (displayedSession === null) {
      return (
        <div className="space-y-4">
          <p className="text-sm text-muted-foreground">Chưa có session. Tạo từ Capital Planner.</p>
          <button
            type="button"
            className="text-sm font-medium text-primary underline"
            onClick={() => {
              setActiveWorkspace('capital');
            }}
          >
            Mở Capital Planner
          </button>
        </div>
      );
    }

    const preset = findPreset(allPresets, displayedSession.presetId);
    const minimalSessionMode = displayedSession.originDraftId !== undefined;
    const isReadOnly =
      readOnlySession ||
      (displayedSession.status !== 'playing' && displayedSession.status !== 'draft');

    return (
      <SessionPlannerScreen
        session={displayedSession}
        preset={preset}
        view={sessionView}
        continuePolicy={continuePolicy}
        planCandidate={persisted.planCandidate}
        latestDraw={latestDraw}
        onViewChange={setSessionView}
        onStartPlan={isReadOnly ? () => undefined : startPlan}
        onContinue={isReadOnly ? () => undefined : (target) => void handleContinue(target)}
        onSelectImproveOption={
          isReadOnly ? () => undefined : (option) => void handleSelectImproveOption(option)
        }
        onPromoteCandidate={isReadOnly ? () => undefined : () => void handlePromoteCandidate()}
        onDiscardCandidate={isReadOnly ? () => undefined : () => void handleDiscardCandidate()}
        onNotesChange={handleNotesChange}
        onTitleChange={handleTitleChange}
        onExport={handleExportSession}
        onStopSession={isReadOnly ? () => undefined : handleStopSession}
        readOnly={isReadOnly}
        minimalMode={minimalSessionMode}
      />
    );
  }

  function renderMain(): JSX.Element {
    if (!hydrated) {
      return (
        <div className="flex min-h-[40vh] items-center justify-center text-sm text-muted-foreground">
          Đang tải…
        </div>
      );
    }

    switch (activeWorkspace) {
      case 'dashboard':
        return (
          <DashboardScreen
            activeSession={activeSession}
            preset={
              activeSession !== null ? findPreset(allPresets, activeSession.presetId) : undefined
            }
            presets={allPresets}
            recommendationSet={persisted.recommendationSet}
            gameStatistics={gameStatistics}
            gameDraws={gameDraws}
            gameStatisticsLoading={gameStatisticsLoading}
            gameStatisticsError={gameStatisticsError}
            onRefreshGameStatistics={refreshGameStatistics}
            notifications={persisted.notifications}
            onOpenNotifications={() => {
              setActiveWorkspace('settings');
            }}
            latestDraw={latestDraw}
            capitalOverview={capitalOverview}
            onOpenSession={() => {
              setViewingSessionId(null);
              setActiveWorkspace('session');
            }}
            onNewSession={() => {
              setViewingSessionId(null);
              setActiveWorkspace('capital');
            }}
            onOpenCapitalPlanner={() => {
              setActiveWorkspace('capital');
            }}
          />
        );
      case 'game-monitor':
        return <GameMonitorScreen />;
      case 'game-designer':
        return (
          <GameDesignerScreen
            customPresets={persisted.customGamePresets}
            activePresetId={persisted.activePresetId}
            onSavePreset={handleSaveGamePreset}
            onDeletePreset={handleDeleteGamePreset}
            onSelectPreset={(id) => {
              const preset = findPreset(allPresets, id);
              if (preset !== undefined) {
                handlePresetSelect(preset);
              }
            }}
          />
        );
      case 'scenario':
        return renderScenarioWorkspace();
      case 'capital':
        return renderCapitalWorkspace();
      case 'session':
        return renderSessionWorkspace();
      case 'planning':
        return renderPlanningWorkspace();
      case 'analysis':
        return (
          <InsightsScreen
            sessions={persisted.sessions}
            presets={allPresets}
            capitalPlanner={persisted.capitalPlanner}
            gameStatistics={gameStatistics}
            onNavigate={(ws) => {
              setActiveWorkspace(ws);
            }}
            onOpenSession={(id) => {
              setViewingSessionId(id);
              setSessionView('overview');
              setActiveWorkspace('session');
            }}
          />
        );
      case 'allocation':
        return <AllocationScreen />;
      case 'history':
        return (
          <SessionLibraryScreen
            sessions={persisted.sessions}
            activeSessionId={persisted.activeSessionId}
            presets={allPresets}
            collections={persisted.libraryCollections}
            onOpenSession={(id) => {
              setViewingSessionId(id);
              setSessionView('overview');
              setActiveWorkspace('session');
            }}
            onToggleFavorite={(id) => {
              runLibrarySessionMutation(id, (s) => toggleSessionFavorite(s));
            }}
            onToggleArchive={(id) => {
              runLibrarySessionMutation(id, (s) => toggleSessionArchived(s));
            }}
            onDuplicate={(id) => {
              void duplicateLibrarySessionUseCase.execute(id).then((result) => {
                if (!result.ok) {
                  return;
                }
                applyPersistedState(result.nextState);
                setViewingSessionId(result.session.id);
                setSessionView('overview');
                setActiveWorkspace('session');
                showToast('Đặt tên session mới');
              });
            }}
            onExportJson={(id) => {
              const session = findSession(persisted.sessions, id);
              if (session !== null) {
                exportFullSessionJson(session);
              }
            }}
            onExportPrint={(id) => {
              const session = findSession(persisted.sessions, id);
              if (session === null) {
                return;
              }
              const preset = findPreset(allPresets, session.presetId);
              exportSessionPrint(session, preset?.name ?? session.presetId);
            }}
            onTagAdd={(id, tag) => {
              runLibrarySessionMutation(id, (s) =>
                s.tags.includes(tag) ? s : updateSessionTags(s, [...s.tags, tag]),
              );
            }}
            onAddCollection={(collection: LibraryCollection) => {
              void addLibraryCollectionUseCase.execute(collection).then((result) => {
                applyPersistedState(result.nextState);
                showToast(`Collection "${collection.name}" đã thêm`);
              });
            }}
          />
        );
      case 'diagnostics':
        return (
          <DiagnosticsProvider capabilities={diagnosticCapabilities}>
            <DiagnosticsPage />
          </DiagnosticsProvider>
        );
      case 'settings':
        return (
          <SettingsScreen
            theme={persisted.theme}
            onThemeChange={(dark) => {
              persist({ ...persisted, theme: dark ? 'dark' : 'light' });
            }}
            notificationPreferences={persisted.notificationPreferences}
            onNotificationPreferencesChange={updateNotificationPreferences}
            onExportHistory={() => {
              exportLibraryJson(persisted.sessions);
              showToast('Đã xuất Session Library JSON');
            }}
          />
        );
      default:
        return renderSessionWorkspace();
    }
  }

  const showRightPanel =
    activeWorkspace === 'planning' || (activeWorkspace === 'session' && sessionView === 'playing');

  const rightPanel =
    activeWorkspace === 'planning' ? (
      <FormRightPanel form={liveForm} />
    ) : currentPlan !== null && activeWorkspace === 'session' && sessionView === 'playing' ? (
      <>
        <PlayingProgressPanel
          completedThroughRound={currentPlan.completedThroughRound}
          totalRounds={currentPlan.generated.strategy.rounds.length}
        />
        <PlanRightPanel
          generated={currentPlan.generated}
          completedThroughRound={currentPlan.completedThroughRound}
        />
      </>
    ) : (
      <FormRightPanel form={liveForm} />
    );

  return (
    <ShellProvider runtime={shellRuntime} appContext={shellAppContext}>
      <CollectorStatusProvider value={collectorStatusSnapshot}>
        <CloudStatusProvider value={cloudStatusSnapshot}>
          <SessionStatusProvider value={sessionStatusSnapshot}>
            <BuildStatusProvider value={buildStatusSnapshot}>
              <ThemeProvider mode={persisted.theme}>
                <AppLayout
                  activeWorkspace={activeWorkspace}
                  onWorkspaceSelect={(ws) => {
                    if (ws !== 'session') {
                      setViewingSessionId(null);
                    }
                    setActiveWorkspace(ws);
                  }}
                  theme={persisted.theme}
                  onThemeChange={(dark) => {
                    persist({ ...persisted, theme: dark ? 'dark' : 'light' });
                  }}
                  showRightPanel={showRightPanel}
                  main={renderMain()}
                  rightPanel={rightPanel}
                  statusBar={<StatusBar />}
                  notifications={persisted.notifications}
                  notificationUnreadCount={notificationUnreadCount}
                  onNotificationMarkRead={markNotificationRead}
                  onNotificationMarkAllRead={markAllNotificationsRead}
                  onNotificationClearAll={clearAllNotifications}
                  onNotificationOpenSession={(id) => {
                    setViewingSessionId(id);
                    setSessionView('overview');
                    setActiveWorkspace('session');
                  }}
                />
                {toast !== null ? (
                  <ActionToast
                    message={toast.message}
                    {...(toast.actionLabel !== undefined ? { actionLabel: toast.actionLabel } : {})}
                    {...(toast.onAction !== undefined ? { onAction: toast.onAction } : {})}
                    onClose={() => {
                      setToast(null);
                    }}
                  />
                ) : null}
              </ThemeProvider>
            </BuildStatusProvider>
          </SessionStatusProvider>
        </CloudStatusProvider>
      </CollectorStatusProvider>
    </ShellProvider>
  );
}

import type { CollectorHealthResponse } from '@/features/game-monitor/collector-api-types';
import type { DiagnosticSnapshot } from '@/product-shell/types/diagnostics';
import type { DiagnosticsPorts } from '@/product-shell/ui/diagnostics/create-capabilities';
import { refreshPersistenceCapability } from '@/product-shell/ui/diagnostics/persistence-capability';

function nowIso(): string {
  return new Date().toISOString();
}

function snapshot(
  severity: DiagnosticSnapshot['severity'],
  summary: string,
  rows: DiagnosticSnapshot['rows'],
  status: DiagnosticSnapshot['status'] = severity === 'critical' ? 'error' : severity === 'warning' ? 'warning' : 'ok',
): DiagnosticSnapshot {
  return {
    status,
    severity,
    summary,
    rows,
    checkedAt: nowIso(),
  };
}

export interface AppDiagnosticsDeps {
  readonly fetchCollectorHealth: () => Promise<CollectorHealthResponse | null>;
  readonly notificationCount: number;
  readonly unreadNotificationCount: number;
  readonly statisticsError: string | null;
  readonly statisticsLoading: boolean;
  readonly statisticsDrawCount: number | null;
  readonly cloudEnabled: boolean;
  readonly buildVersion: string;
  readonly runtimeHealthy: boolean;
}

function mapCollectorHealth(health: CollectorHealthResponse | null): DiagnosticSnapshot {
  if (health === null) {
    return snapshot(
      'critical',
      'Collector unreachable',
      [
        { label: 'Status', value: 'offline' },
        { label: 'Hint', value: 'Start collector service on localhost:8788' },
      ],
      'error',
    );
  }

  const severity =
    health.status === 'running' ? 'info' : health.status === 'degraded' ? 'warning' : 'critical';
  return snapshot(
    severity,
    `${health.drawCount.toLocaleString()} draws · ${health.activeAdapterId}`,
    [
      { label: 'Status', value: health.status },
      { label: 'Last draw', value: health.lastDrawKey ?? '—' },
      { label: 'Failures', value: String(health.failureCount) },
    ],
    health.status === 'running' ? 'ok' : health.status === 'degraded' ? 'warning' : 'error',
  );
}

export function createAppDiagnosticsPorts(deps: AppDiagnosticsDeps): DiagnosticsPorts {
  return {
    refreshCollector: async () => mapCollectorHealth(await deps.fetchCollectorHealth()),

    refreshStorage: refreshPersistenceCapability,

    refreshRuntime: async () =>
      snapshot(
        deps.runtimeHealthy ? 'info' : 'warning',
        deps.runtimeHealthy ? 'Product Shell runtime healthy' : 'Runtime reported warnings',
        [
          { label: 'Build', value: deps.buildVersion },
          { label: 'Shell', value: 'product-shell-v0.5+' },
        ],
        deps.runtimeHealthy ? 'ok' : 'warning',
      ),

    refreshNotifications: async () =>
      snapshot('info', `${deps.unreadNotificationCount} unread notifications`, [
        { label: 'Total', value: String(deps.notificationCount) },
        { label: 'Unread', value: String(deps.unreadNotificationCount) },
      ]),

    refreshStatistics: async () => {
      if (deps.statisticsError !== null) {
        return snapshot(
          'critical',
          'Statistics unavailable',
          [{ label: 'Error', value: deps.statisticsError }],
          'error',
        );
      }
      if (deps.statisticsLoading) {
        return snapshot('warning', 'Statistics refresh in progress', [
          { label: 'State', value: 'loading' },
        ]);
      }
      return snapshot(
        'info',
        deps.statisticsDrawCount !== null
          ? `${deps.statisticsDrawCount.toLocaleString()} draws in statistics cache`
          : 'Statistics ready',
        [
          {
            label: 'Draw count',
            value: deps.statisticsDrawCount !== null ? String(deps.statisticsDrawCount) : '—',
          },
        ],
      );
    },

    refreshCloud: async () =>
      snapshot(
        'info',
        deps.cloudEnabled ? 'Cloud enabled' : 'Cloud disabled',
        [{ label: 'Phase', value: deps.cloudEnabled ? 'enabled' : 'disabled (Product Evolution)' }],
        deps.cloudEnabled ? 'ok' : 'disabled',
      ),
  };
}

import { useMemo, type ReactNode } from 'react';

import { Button } from '@/components/ui/button';
import {
  CHART_TIME_PERIOD_LABELS,
  CHART_TIME_PERIODS,
  dateKeyToReferenceInstant,
  getChartPeriodStart,
  toGameDateKey,
  type ChartPeriodSelection,
  type ChartTimePeriod,
} from '@/features/game-data/statistics/draw-period';
import { cn } from '@/lib/utils';

export interface ChartPeriodSelectorProps {
  readonly value: ChartPeriodSelection;
  readonly onChange: (next: ChartPeriodSelection) => void;
  /** YYYY-MM-DD → số kỳ trong DB (hiển thị trên lịch). */
  readonly dailyCounts?: Readonly<Record<string, number>>;
}

const WEEKDAY_LABELS = ['T2', 'T3', 'T4', 'T5', 'T6', 'T7', 'CN'] as const;
const MONTH_SHORT = ['T1', 'T2', 'T3', 'T4', 'T5', 'T6', 'T7', 'T8', 'T9', 'T10', 'T11', 'T12'] as const;

function shiftReference(
  period: ChartTimePeriod,
  referenceDate: Date,
  delta: number,
): Date {
  const p = toGameDateKey(referenceDate).split('-').map(Number) as [number, number, number];
  const [year, month] = p;

  switch (period) {
    case 'day':
      return dateKeyToReferenceInstant(
        toGameDateKey(new Date(referenceDate.getTime() + delta * 86_400_000)),
      );
    case 'week':
      return dateKeyToReferenceInstant(
        toGameDateKey(new Date(referenceDate.getTime() + delta * 7 * 86_400_000)),
      );
    case 'month': {
      const d = new Date(`${String(year)}-${String(month).padStart(2, '0')}-15T12:00:00+07:00`);
      d.setMonth(d.getMonth() + delta);
      return d;
    }
    case 'quarter': {
      const d = new Date(`${String(year)}-${String(month).padStart(2, '0')}-15T12:00:00+07:00`);
      d.setMonth(d.getMonth() + delta * 3);
      return d;
    }
    case 'year':
      return dateKeyToReferenceInstant(`${String(year + delta)}-06-15`);
  }
}

function buildMonthGrid(viewYear: number, viewMonth: number): readonly (string | null)[] {
  const first = new Date(`${String(viewYear)}-${String(viewMonth).padStart(2, '0')}-01T12:00:00+07:00`);
  const firstKey = toGameDateKey(first);
  const firstWeekday = new Date(`${firstKey}T12:00:00+07:00`).getUTCDay();
  const mondayOffset = firstWeekday === 0 ? 6 : firstWeekday - 1;
  const daysInMonth = new Date(viewYear, viewMonth, 0).getDate();

  const cells: (string | null)[] = [];
  for (let i = 0; i < mondayOffset; i += 1) {
    cells.push(null);
  }
  for (let d = 1; d <= daysInMonth; d += 1) {
    cells.push(
      `${String(viewYear)}-${String(viewMonth).padStart(2, '0')}-${String(d).padStart(2, '0')}`,
    );
  }
  while (cells.length % 7 !== 0) {
    cells.push(null);
  }
  return cells;
}

function isDateInWeek(dateKey: string, referenceDate: Date): boolean {
  const weekStart = toGameDateKey(getChartPeriodStart('week', referenceDate));
  const weekEnd = toGameDateKey(
    new Date(getChartPeriodStart('week', referenceDate).getTime() + 6 * 86_400_000),
  );
  return dateKey >= weekStart && dateKey <= weekEnd;
}

export function ChartPeriodSelector({
  value,
  onChange,
  dailyCounts = {},
}: ChartPeriodSelectorProps): ReactNode {
  const { period, referenceDate } = value;
  const refKey = toGameDateKey(referenceDate);
  const [viewYear, viewMonth] = refKey.split('-').map(Number) as [number, number];
  const todayKey = toGameDateKey(new Date());

  const monthCells = useMemo(
    () => buildMonthGrid(viewYear, viewMonth),
    [viewYear, viewMonth],
  );

  const setPeriod = (nextPeriod: ChartTimePeriod): void => {
    onChange({ period: nextPeriod, referenceDate });
  };

  const setReference = (nextDate: Date): void => {
    onChange({ period, referenceDate: nextDate });
  };

  const selectDateKey = (dateKey: string): void => {
    setReference(dateKeyToReferenceInstant(dateKey));
  };

  return (
    <div className="space-y-3 rounded-lg border border-border bg-muted/30 p-3">
      <div className="flex flex-wrap gap-1">
        {CHART_TIME_PERIODS.map((p) => (
          <Button
            key={p}
            type="button"
            size="sm"
            variant={period === p ? 'default' : 'outline'}
            className="h-8 px-3 text-xs"
            onClick={() => {
              setPeriod(p);
            }}
          >
            {CHART_TIME_PERIOD_LABELS[p]}
          </Button>
        ))}
      </div>

      <div className="flex items-center justify-between gap-2">
        <Button
          type="button"
          size="sm"
          variant="ghost"
          className="h-8 px-2 text-xs"
          onClick={() => {
            setReference(shiftReference(period, referenceDate, -1));
          }}
        >
          ←
        </Button>
        <span className="text-center text-xs font-medium text-foreground">
          {period === 'day' || period === 'week'
            ? `${MONTH_SHORT[viewMonth - 1]} ${String(viewYear)}`
            : period === 'month'
              ? String(viewYear)
              : period === 'quarter' || period === 'year'
                ? `Năm ${String(viewYear)}`
                : ''}
        </span>
        <Button
          type="button"
          size="sm"
          variant="ghost"
          className="h-8 px-2 text-xs"
          onClick={() => {
            setReference(shiftReference(period, referenceDate, 1));
          }}
        >
          →
        </Button>
      </div>

      {period === 'day' || period === 'week' ? (
        <div>
          <div className="mb-1 grid grid-cols-7 gap-0.5">
            {WEEKDAY_LABELS.map((label) => (
              <div
                key={label}
                className="py-1 text-center text-[10px] font-medium uppercase text-muted-foreground"
              >
                {label}
              </div>
            ))}
          </div>
          <div className="grid grid-cols-7 gap-0.5">
            {monthCells.map((dateKey, index) => {
              if (dateKey === null) {
                return <div key={`empty-${String(index)}`} className="h-8" />;
              }
              const dayNum = Number(dateKey.slice(8, 10));
              const dayCount = dailyCounts[dateKey];
              const isSelected =
                period === 'day'
                  ? dateKey === refKey
                  : isDateInWeek(dateKey, referenceDate);
              const isToday = dateKey === todayKey;
              return (
                <button
                  key={dateKey}
                  type="button"
                  className={cn(
                    'flex min-h-10 flex-col items-center justify-center rounded px-0.5 text-xs font-medium transition-colors',
                    isSelected
                      ? 'bg-foreground text-background'
                      : 'hover:bg-muted',
                    isToday && !isSelected ? 'ring-1 ring-foreground/40' : '',
                    dateKey > todayKey ? 'opacity-40' : '',
                    dayCount === undefined ? 'opacity-60' : '',
                  )}
                  disabled={dateKey > todayKey}
                  onClick={() => {
                    selectDateKey(dateKey);
                  }}
                >
                  <span>{dayNum}</span>
                  {dayCount !== undefined ? (
                    <span
                      className={cn(
                        'text-[9px] font-normal leading-none',
                        isSelected ? 'text-background/80' : 'text-muted-foreground',
                      )}
                    >
                      {dayCount}
                    </span>
                  ) : null}
                </button>
              );
            })}
          </div>
        </div>
      ) : null}

      {period === 'month' ? (
        <div className="grid grid-cols-4 gap-2">
          {MONTH_SHORT.map((label, index) => {
            const month = index + 1;
            const isSelected = viewMonth === month;
            const monthKey = `${String(viewYear)}-${String(month).padStart(2, '0')}`;
            const isFuture = monthKey > todayKey.slice(0, 7);
            const monthTotal = Object.entries(dailyCounts).reduce((sum, [day, count]) => {
              return day.startsWith(monthKey) ? sum + count : sum;
            }, 0);
            return (
              <Button
                key={label}
                type="button"
                size="sm"
                variant={isSelected ? 'default' : 'outline'}
                className="h-auto min-h-9 flex-col py-1 text-xs"
                disabled={isFuture}
                onClick={() => {
                  selectDateKey(`${monthKey}-15`);
                }}
              >
                <span>{label}</span>
                {monthTotal > 0 ? (
                  <span className="text-[9px] font-normal opacity-80">{monthTotal} kỳ</span>
                ) : null}
              </Button>
            );
          })}
        </div>
      ) : null}

      {period === 'quarter' ? (
        <div className="grid grid-cols-4 gap-2">
          {[1, 2, 3, 4].map((q) => {
            const quarterMonth = (q - 1) * 3 + 1;
            const isSelected = Math.floor((viewMonth - 1) / 3) + 1 === q;
            const quarterKey = `${String(viewYear)}-${String(quarterMonth).padStart(2, '0')}`;
            const isFuture = quarterKey > todayKey.slice(0, 7);
            return (
              <Button
                key={q}
                type="button"
                size="sm"
                variant={isSelected ? 'default' : 'outline'}
                className="h-9 text-xs"
                disabled={isFuture}
                onClick={() => {
                  selectDateKey(`${String(viewYear)}-${String(quarterMonth).padStart(2, '0')}-15`);
                }}
              >
                Q{q}
              </Button>
            );
          })}
        </div>
      ) : null}

      {period === 'year' ? (
        <div className="flex flex-wrap justify-center gap-2">
          {[viewYear - 1, viewYear, viewYear + 1].map((y) => {
            const isSelected = y === viewYear;
            const isFuture = y > Number(todayKey.slice(0, 4));
            return (
              <Button
                key={y}
                type="button"
                size="sm"
                variant={isSelected ? 'default' : 'outline'}
                className="h-9 min-w-[4rem] text-xs"
                disabled={isFuture}
                onClick={() => {
                  selectDateKey(`${String(y)}-06-15`);
                }}
              >
                {y}
              </Button>
            );
          })}
        </div>
      ) : null}

      <Button
        type="button"
        size="sm"
        variant="ghost"
        className="h-8 w-full text-xs text-muted-foreground"
        onClick={() => {
          onChange({ period, referenceDate: new Date() });
        }}
      >
        Về hôm nay
      </Button>
    </div>
  );
}

import type { DrawRecord } from '@/features/game-data/statistics/statistics-types';

export type ChartTimePeriod = 'day' | 'week' | 'month' | 'quarter' | 'year';

export const CHART_TIME_PERIODS: readonly ChartTimePeriod[] = [
  'day',
  'week',
  'month',
  'quarter',
  'year',
];

export const CHART_TIME_PERIOD_LABELS: Record<ChartTimePeriod, string> = {
  day: 'Ngày',
  week: 'Tuần',
  month: 'Tháng',
  quarter: 'Quý',
  year: 'Năm',
};

/** Bingo18 wall-clock — always Vietnam (+07). */
export const GAME_TIME_ZONE = 'Asia/Ho_Chi_Minh';

const MIN_YEAR = 2000;
const MAX_YEAR = 2100;

export interface ChartPeriodBounds {
  readonly start: Date;
  readonly end: Date;
}

export interface ChartPeriodSelection {
  readonly period: ChartTimePeriod;
  /** Any instant inside the selected calendar period (game TZ). */
  readonly referenceDate: Date;
}

export interface DrawKeyBounds {
  readonly fromKey: string;
  readonly toKey: string;
}

function pad2(value: number): string {
  return String(value).padStart(2, '0');
}

type GameParts = {
  readonly year: number;
  readonly month: number;
  readonly day: number;
  readonly hour: number;
  readonly minute: number;
  readonly second: number;
};

function readGameParts(instant: Date): GameParts {
  const formatter = new Intl.DateTimeFormat('en-GB', {
    timeZone: GAME_TIME_ZONE,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
  });
  const parts = Object.fromEntries(
    formatter.formatToParts(instant).map((part) => [part.type, part.value]),
  );
  return {
    year: Number(parts['year']),
    month: Number(parts['month']),
    day: Number(parts['day']),
    hour: Number(parts['hour']),
    minute: Number(parts['minute']),
    second: Number(parts['second']),
  };
}

function gameDateKey(parts: Pick<GameParts, 'year' | 'month' | 'day'>): string {
  return `${String(parts.year)}-${pad2(parts.month)}-${pad2(parts.day)}`;
}

/** YYYY-MM-DD in game timezone. */
export function toGameDateKey(instant: Date): string {
  return gameDateKey(readGameParts(instant));
}

export function dateKeyToReferenceInstant(dateKey: string): Date {
  return new Date(`${dateKey}T12:00:00+07:00`);
}

export function toDrawKeyFromInstant(instant: Date): string {
  const p = readGameParts(instant);
  return (
    `${String(p.year)}${pad2(p.month)}${pad2(p.day)}` +
    `${pad2(p.hour)}${pad2(p.minute)}${pad2(p.second)}`
  );
}

function gameMidnight(year: number, month: number, day: number): Date {
  return new Date(`${String(year)}-${pad2(month)}-${pad2(day)}T00:00:00+07:00`);
}

function gameEndOfDay(year: number, month: number, day: number): Date {
  return new Date(`${String(year)}-${pad2(month)}-${pad2(day)}T23:59:59+07:00`);
}

function gameEndOfMonth(year: number, month: number): Date {
  const lastDay = new Date(year, month, 0).getDate();
  return gameEndOfDay(year, month, lastDay);
}

function gameEndOfQuarter(year: number, quarterMonth: number): Date {
  return gameEndOfMonth(year, quarterMonth + 3);
}

/** Parse draw wall-clock to epoch ms; supports ISO drawAt or 14-digit drawKey. */
export function resolveDrawInstant(draw: DrawRecord): number | null {
  if (/^\d{14}$/.test(draw.drawKey)) {
    const k = draw.drawKey;
    const fromKey = Date.parse(
      `${k.slice(0, 4)}-${k.slice(4, 6)}-${k.slice(6, 8)}T${k.slice(8, 10)}:${k.slice(10, 12)}:${k.slice(12, 14)}+07:00`,
    );
    if (!Number.isNaN(fromKey)) {
      return fromKey;
    }
  }

  const parsedAt = Date.parse(draw.drawAt);
  if (!Number.isNaN(parsedAt)) {
    const year = new Date(parsedAt).getFullYear();
    if (year >= MIN_YEAR && year <= MAX_YEAR) {
      return parsedAt;
    }
  }

  return null;
}

function getDrawGameDateKey(draw: DrawRecord): string | null {
  if (/^\d{14}$/.test(draw.drawKey)) {
    const k = draw.drawKey;
    return `${k.slice(0, 4)}-${k.slice(4, 6)}-${k.slice(6, 8)}`;
  }
  const instant = resolveDrawInstant(draw);
  return instant === null ? null : toGameDateKey(new Date(instant));
}

function gameWeekday(year: number, month: number, day: number): number {
  return new Date(`${String(year)}-${pad2(month)}-${pad2(day)}T12:00:00+07:00`).getUTCDay();
}

/** Start of calendar period in game timezone (inclusive). */
export function getChartPeriodStart(
  period: ChartTimePeriod,
  referenceDate: Date = new Date(),
): Date {
  const p = readGameParts(referenceDate);

  switch (period) {
    case 'day':
      return gameMidnight(p.year, p.month, p.day);
    case 'week': {
      const wd = gameWeekday(p.year, p.month, p.day);
      const mondayOffset = wd === 0 ? 6 : wd - 1;
      const midnight = gameMidnight(p.year, p.month, p.day);
      return new Date(midnight.getTime() - mondayOffset * 86_400_000);
    }
    case 'month':
      return gameMidnight(p.year, p.month, 1);
    case 'quarter': {
      const quarterMonth = Math.floor((p.month - 1) / 3) * 3 + 1;
      return gameMidnight(p.year, quarterMonth, 1);
    }
    case 'year':
      return gameMidnight(p.year, 1, 1);
  }
}

/** Inclusive bounds — `clock` is real now; only cap end when period includes today. */
export function getChartPeriodBounds(
  period: ChartTimePeriod,
  referenceDate: Date = new Date(),
  clock: Date = new Date(),
): ChartPeriodBounds {
  const start = getChartPeriodStart(period, referenceDate);
  const p = readGameParts(referenceDate);
  const todayKey = toGameDateKey(clock);

  let periodEnd: Date;
  switch (period) {
    case 'day':
      periodEnd = gameEndOfDay(p.year, p.month, p.day);
      break;
    case 'week': {
      const weekEnd = new Date(start.getTime() + 6 * 86_400_000);
      const we = readGameParts(weekEnd);
      periodEnd = gameEndOfDay(we.year, we.month, we.day);
      break;
    }
    case 'month':
      periodEnd = gameEndOfMonth(p.year, p.month);
      break;
    case 'quarter': {
      const quarterMonth = Math.floor((p.month - 1) / 3) * 3 + 1;
      periodEnd = gameEndOfQuarter(p.year, quarterMonth);
      break;
    }
    case 'year':
      periodEnd = gameEndOfDay(p.year, 12, 31);
      break;
  }

  const periodIncludesToday = isDrawInChartPeriod(todayKey, period, referenceDate);

  if (!periodIncludesToday) {
    return { start, end: periodEnd };
  }

  const nowParts = readGameParts(clock);
  const actualNow = new Date(
    Date.parse(
      `${gameDateKey(nowParts)}T${pad2(nowParts.hour)}:${pad2(nowParts.minute)}:${pad2(nowParts.second)}+07:00`,
    ),
  );

  return {
    start,
    end: new Date(Math.min(periodEnd.getTime(), actualNow.getTime())),
  };
}

/** YYYYMMDD compact key for SQL day filter. */
export function toGameDayCompact(dateKey: string): string {
  return dateKey.replace(/-/g, '');
}

export function compactDayFromReference(referenceDate: Date): string {
  return toGameDayCompact(toGameDateKey(referenceDate));
}

/** draw_key range for Collector — reliable vs mixed draw_at ISO strings. */
export function getDrawKeyBounds(
  period: ChartTimePeriod,
  referenceDate: Date = new Date(),
): DrawKeyBounds {
  const { start, end } = getChartPeriodBounds(period, referenceDate);
  const startParts = readGameParts(start);
  return {
    fromKey: `${String(startParts.year)}${pad2(startParts.month)}${pad2(startParts.day)}000000`,
    toKey: toDrawKeyFromInstant(end),
  };
}

/** ISO with +07:00 for legacy between API. */
export function toGameOffsetIso(instant: Date): string {
  const p = readGameParts(instant);
  return (
    `${gameDateKey(p)}T${pad2(p.hour)}:${pad2(p.minute)}:${pad2(p.second)}+07:00`
  );
}

function isSameGameMonth(aKey: string, bKey: string): boolean {
  return aKey.slice(0, 7) === bKey.slice(0, 7);
}

function isSameGameQuarter(aKey: string, bKey: string): boolean {
  return (
    aKey.slice(0, 4) === bKey.slice(0, 4) &&
    Math.floor((Number(aKey.slice(5, 7)) - 1) / 3) ===
      Math.floor((Number(bKey.slice(5, 7)) - 1) / 3)
  );
}

function isSameGameWeek(aKey: string, bKey: string): boolean {
  return toGameDateKey(getChartPeriodStart('week', dateKeyToReferenceInstant(aKey))) ===
    toGameDateKey(getChartPeriodStart('week', dateKeyToReferenceInstant(bKey)));
}

function isDrawInChartPeriod(
  drawDateKey: string,
  period: ChartTimePeriod,
  referenceDate: Date,
): boolean {
  const refKey = toGameDateKey(referenceDate);
  switch (period) {
    case 'day':
      return drawDateKey === refKey;
    case 'week':
      return isSameGameWeek(drawDateKey, refKey);
    case 'month':
      return isSameGameMonth(drawDateKey, refKey);
    case 'quarter':
      return isSameGameQuarter(drawDateKey, refKey);
    case 'year':
      return drawDateKey.slice(0, 4) === refKey.slice(0, 4);
  }
}

export function filterDrawsByChartPeriod(
  draws: readonly DrawRecord[],
  period: ChartTimePeriod,
  referenceDate: Date = new Date(),
): readonly DrawRecord[] {
  const refKey = toGameDateKey(referenceDate);
  const refDayCompact = toGameDayCompact(refKey);

  return draws.filter((draw) => {
    if (period === 'day' && /^\d{14}$/.test(draw.drawKey)) {
      return draw.drawKey.startsWith(refDayCompact);
    }
    const drawDateKey = getDrawGameDateKey(draw);
    if (drawDateKey === null) {
      return false;
    }
    return isDrawInChartPeriod(drawDateKey, period, referenceDate);
  });
}

const VI_MONTHS = [
  'tháng 1',
  'tháng 2',
  'tháng 3',
  'tháng 4',
  'tháng 5',
  'tháng 6',
  'tháng 7',
  'tháng 8',
  'tháng 9',
  'tháng 10',
  'tháng 11',
  'tháng 12',
] as const;

function formatShortDate(dateKey: string): string {
  const [y, m, d] = dateKey.split('-');
  return `${d}/${m}/${y ?? ''}`;
}

/** Human-readable label for chart header. */
export function formatChartPeriodHeading(
  period: ChartTimePeriod,
  referenceDate: Date = new Date(),
): string {
  const refKey = toGameDateKey(referenceDate);
  const [year, month] = refKey.split('-').map(Number);
  const monthIndex = (month ?? 1) - 1;

  switch (period) {
    case 'day':
      return formatShortDate(refKey);
    case 'week': {
      const start = getChartPeriodStart('week', referenceDate);
      const end = new Date(start.getTime() + 6 * 86_400_000);
      return `${formatShortDate(toGameDateKey(start))} – ${formatShortDate(toGameDateKey(end))}`;
    }
    case 'month':
      return `${VI_MONTHS[monthIndex] ?? ''} ${String(year)}`;
    case 'quarter': {
      const q = Math.floor(monthIndex / 3) + 1;
      return `Quý ${String(q)}/${String(year)}`;
    }
    case 'year':
      return `Năm ${String(year)}`;
  }
}

export function defaultChartPeriodSelection(): ChartPeriodSelection {
  return { period: 'day', referenceDate: new Date() };
}

/** Format instant in bingo18 timezone (vi-VN). */
export function formatGameDateTime(
  instant: Date,
  mode: 'date' | 'time' | 'datetime' = 'datetime',
): string {
  const options: Intl.DateTimeFormatOptions =
    mode === 'date'
      ? { year: 'numeric', month: '2-digit', day: '2-digit' }
      : mode === 'time'
        ? { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false }
        : {
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: '2-digit',
            minute: '2-digit',
            second: '2-digit',
            hour12: false,
          };
  return new Intl.DateTimeFormat('vi-VN', { timeZone: GAME_TIME_ZONE, ...options }).format(
    instant,
  );
}

/** Wall-clock range from actual draws — e.g. "08:05 – 21:30". */
export function formatChartPeriodTimeRange(
  draws: readonly { drawKey: string }[],
): string | null {
  const keys = draws
    .map((d) => d.drawKey)
    .filter((k) => /^\d{14}$/.test(k))
    .sort();
  if (keys.length === 0) {
    return null;
  }
  const first = keys[0] ?? '';
  const last = keys[keys.length - 1] ?? '';
  const toTime = (key: string): string => `${key.slice(8, 10)}:${key.slice(10, 12)}`;
  if (toTime(first) === toTime(last)) {
    return `${toTime(first)} (+07)`;
  }
  return `${toTime(first)} – ${toTime(last)} (+07)`;
}

import type { SessionRepository } from '@/services/storage/repositories/session-repository';
import { undoBetOnPlan } from '@/features/session/session-domain';
import type { PersistedAppState } from '@/features/session/session-types';

export interface UndoBetUseCaseDeps {
  readonly sessions: SessionRepository;
}

export type UndoBetResult =
  | { readonly ok: true; readonly nextState: PersistedAppState }
  | { readonly ok: false; readonly reason: 'session-not-found' | 'nothing-to-undo' };

export class UndoBetUseCase {
  constructor(private readonly deps: UndoBetUseCaseDeps) {}

  async execute(sessionId: string): Promise<UndoBetResult> {
    let undone = false;
    const next = await this.deps.sessions.updateSession(sessionId, (session) => {
      const updated = undoBetOnPlan(session);
      if (updated === null) {
        return session;
      }
      undone = true;
      return updated;
    });
    if (next === null) {
      return { ok: false, reason: 'session-not-found' };
    }
    if (!undone) {
      return { ok: false, reason: 'nothing-to-undo' };
    }
    return { ok: true, nextState: next };
  }
}

export function createUndoBetUseCase(deps: UndoBetUseCaseDeps): UndoBetUseCase {
  return new UndoBetUseCase(deps);
}

import { useEffect, useMemo, useRef, useState, type ReactNode } from 'react';

import { zIndexClass } from '@/design/tokens/z-index';
import { cn } from '@/lib/utils';

import { useShell } from '@/product-shell/ui/shell-context';
import {
  buildPaletteRows,
  listSelectableItems,
  type PaletteRow,
} from '@/product-shell/ui/palette/palette-items';

export interface CommandPaletteProps {
  readonly open: boolean;
  readonly onClose: () => void;
}

function outcomeGlyph(outcome: 'success' | 'failure'): string {
  return outcome === 'success' ? '✓' : '✕';
}

export function CommandPalette({ open, onClose }: CommandPaletteProps): ReactNode {
  const { runtime, appContext } = useShell();
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [executing, setExecuting] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  const rows = useMemo((): readonly PaletteRow[] => {
    if (!open) {
      return [];
    }
    return buildPaletteRows({
      query,
      recent: runtime.actionHistory.recent(10),
      visibleCommands: runtime.searchCommands('', appContext).map((entry) => entry.command),
      resolveCommandTitle: (commandId) => runtime.commands.get(commandId)?.title,
    });
  }, [appContext, open, query, runtime]);

  const selectableItems = useMemo(() => listSelectableItems(rows), [rows]);

  useEffect(() => {
    if (!open) {
      setQuery('');
      setSelectedIndex(0);
      setExecuting(false);
      return;
    }
    const frame = window.requestAnimationFrame(() => {
      inputRef.current?.focus();
    });
    return () => {
      window.cancelAnimationFrame(frame);
    };
  }, [open]);

  useEffect(() => {
    setSelectedIndex(0);
  }, [query]);

  async function runSelectedItem(): Promise<void> {
    const selected = selectableItems[selectedIndex];
    if (selected === undefined || executing) {
      return;
    }
    setExecuting(true);
    try {
      const commandId = selected.kind === 'recent' ? selected.commandId : selected.command.id;
      await runtime.executeCommand(commandId, appContext);
      onClose();
    } catch {
      // Failure is recorded in action history; palette stays open.
    } finally {
      setExecuting(false);
    }
  }

  if (!open) {
    return null;
  }

  let selectableCursor = -1;

  return (
    <div
      className={cn('fixed inset-0 flex items-start justify-center bg-black/50 px-4 pt-[12vh]', zIndexClass.commandPalette)}
      role="presentation"
      onMouseDown={(event) => {
        if (event.target === event.currentTarget) {
          onClose();
        }
      }}
    >
      <div
        className="w-full max-w-xl overflow-hidden rounded-xl border border-border bg-card shadow-2xl"
        role="dialog"
        aria-modal="true"
        aria-label="Command palette"
        onKeyDown={(event) => {
          if (event.key === 'Escape') {
            event.preventDefault();
            onClose();
            return;
          }
          if (event.key === 'ArrowDown') {
            event.preventDefault();
            setSelectedIndex((index) =>
              Math.min(index + 1, Math.max(selectableItems.length - 1, 0)),
            );
            return;
          }
          if (event.key === 'ArrowUp') {
            event.preventDefault();
            setSelectedIndex((index) => Math.max(index - 1, 0));
            return;
          }
          if (event.key === 'Enter') {
            event.preventDefault();
            void runSelectedItem();
          }
        }}
      >
        <div className="border-b border-border px-4 py-3">
          <input
            ref={inputRef}
            type="text"
            value={query}
            placeholder="Search commands…"
            className="w-full bg-transparent text-sm outline-none placeholder:text-muted-foreground"
            aria-label="Search commands"
            onChange={(event) => {
              setQuery(event.target.value);
            }}
          />
        </div>
        <ul className="max-h-80 overflow-y-auto py-2" role="listbox">
          {rows.length === 0 ? (
            <li className="px-4 py-3 text-sm text-muted-foreground">No matching commands</li>
          ) : (
            rows.map((row, index) => {
              if (row.kind === 'header') {
                return (
                  <li
                    key={`header-${row.label}-${index}`}
                    className="px-4 pb-1 pt-2 text-[11px] font-semibold uppercase tracking-wide text-muted-foreground"
                  >
                    {row.label}
                  </li>
                );
              }

              selectableCursor += 1;
              const active = selectableCursor === selectedIndex;
              const label = row.kind === 'recent' ? row.title : row.command.title;
              const description = row.kind === 'command' ? row.command.description : undefined;

              return (
                <li key={row.kind === 'recent' ? `recent-${row.commandId}` : row.command.id} role="presentation">
                  <button
                    type="button"
                    role="option"
                    aria-selected={active}
                    className={cn(
                      'flex w-full items-start gap-2 px-4 py-2 text-left text-sm transition-colors',
                      active ? 'bg-accent text-accent-foreground' : 'hover:bg-muted',
                    )}
                    onMouseEnter={() => {
                      setSelectedIndex(selectableCursor);
                    }}
                    onClick={() => {
                      setSelectedIndex(selectableCursor);
                      void runSelectedItem();
                    }}
                  >
                    {row.kind === 'recent' ? (
                      <span aria-hidden className="mt-0.5 w-4 shrink-0 text-xs">
                        {outcomeGlyph(row.outcome)}
                      </span>
                    ) : null}
                    <span className="flex min-w-0 flex-col">
                      <span className="font-medium">{label}</span>
                      {description !== undefined ? (
                        <span className="text-xs text-muted-foreground">{description}</span>
                      ) : null}
                    </span>
                  </button>
                </li>
              );
            })
          )}
        </ul>
      </div>
    </div>
  );
}

import type { ShellRuntime } from '@/product-shell/runtime/shell-runtime';

export interface ShellCommandHandlers {
  readonly openPalette: () => void;
}

export function registerShellCommands(
  shell: ShellRuntime,
  handlers: ShellCommandHandlers,
): void {
  shell.registerCommand({
    id: 'shell.open-palette',
    title: 'Command Palette',
    category: 'Navigation',
    keywords: ['palette', 'commands', 'search'],
    visible: () => true,
    enabled: () => true,
    execute: async () => {
      handlers.openPalette();
    },
  });

  shell.registerCommand({
    id: 'navigation.open-planning',
    title: 'Open Planning',
    category: 'Navigation',
    keywords: ['plan', 'planning', 'generate'],
    visible: () => true,
    enabled: () => true,
    execute: async (ctx) => {
      ctx.navigate('planning');
    },
  });

  shell.registerCommand({
    id: 'navigation.open-session',
    title: 'Open Session',
    category: 'Session',
    keywords: ['session', 'playing', 'continue'],
    visible: () => true,
    enabled: () => true,
    execute: async (ctx) => {
      ctx.navigate('session');
