import { describe, expect, it, vi } from 'vitest';

import { applySettlementToSession } from '@/features/game-data/settlement/apply-settlement-use-case';
import {
  applyMarketToForm,
  applyPresetToForm,
  mergePresets,
} from '@/features/game-designer/preset-utils';
import { DEFAULT_PLANNER_FORM, generatePlan } from '@/features/planner/plan-service';
import { createInitialPlan } from '@/features/session/plan-factory';
import {
  getCurrentPlan,
  placeBetOnPlan,
  startCurrentPlan,
  type Session,
} from '@/features/session/session-domain';
import { EMPTY_PERSISTED_STATE } from '@/features/session/session-types';
import {
  createSavePlayingSessionUseCase,
  createStartPlanUseCase,
  createStopSessionUseCase,
  createUndoBetUseCase,
  createUpdateSessionUseCase,
  createWinSessionUseCase,
} from '@/features/session/use-cases';
import { FakeClock } from '@/services/clock/fake-clock';
import { EventBus } from '@/services/events/domain-events';
import { MemoryStorageDriver } from '@/services/storage/MemoryStorageDriver';
import { PersistenceService } from '@/services/storage/PersistenceService';
import { SessionRepository } from '@/services/storage/repositories/session-repository';

const presets = mergePresets([]);

const baseDraw = {
  drawKey: '20260629220000',
  gameId: 'bingo18',
  marketVersion: 1,
  drawAt: '2026-06-29T22:00:00+07:00',
  publishedAt: '2026-06-29T22:00:00+07:00',
  publishedEstimated: true,
  collectedAt: '2026-06-29T22:02:01+07:00',
  latencyMs: 121_000,
  source: 'bingo18',
};

function createDeps() {
  const driver = new MemoryStorageDriver();
  const clock = new FakeClock(new Date('2026-06-29T22:00:00+07:00'));
  const events = new EventBus(clock);
  const storage = new PersistenceService(driver, events);
  const sessions = new SessionRepository(storage);
  return { driver, storage, sessions };
}

function minimalPlayingSession(marketId = 'total-4'): Session {
  const preset = presets.find((p) => p.id === 'bingo-120');
  if (preset === undefined) {
    throw new Error('bingo-120 preset missing');
  }
  const formValues = applyMarketToForm(
    applyPresetToForm({ ...DEFAULT_PLANNER_FORM, userBankroll: '10.000.000' }, preset),
    preset,
    marketId,
  );
  const generated = generatePlan(formValues);
  if (generated.result === undefined) {
    throw new Error('Failed to generate plan for test session');
  }
  const plan = createInitialPlan({
    index: 0,
    origin: 'capital',
    formValues,
    generated: generated.result,
    status: 'playing',
    completedThroughRound: 0,
    createdAt: '2026-06-29T21:00:00.000Z',
  });
  return {
    id: crypto.randomUUID(),
    sessionNumber: 1,
    title: 'Session #1',
    presetId: 'bingo-120',
    status: 'playing',
    plans: [plan],
    currentPlanId: plan.id,
    timeline: [],
    notes: '',
    startedAt: '2026-06-29T21:00:00.000Z',
    profitAmount: null,
    favorite: false,
    archived: false,
    tags: [],
    lastSettledDrawKey: null,
    playedRounds: [],
    createdAt: '2026-06-29T21:00:00.000Z',
    updatedAt: '2026-06-29T21:00:00.000Z',
  };
}

function draftSessionFromPlaying(playing: Session): Session {
  const plan = getCurrentPlan(playing);
  if (plan === null) {
    throw new Error('missing plan');
  }
  return {
    ...playing,
    status: 'draft',
    startedAt: null,
    plans: [{ ...plan, status: 'ready', completedThroughRound: 0 }],
  };
}

async function seedState(
  driver: MemoryStorageDriver,
  session: Session,
  activeSessionId: string | null = session.id,
): Promise<void> {
  await driver.put('app-state', {
    ...EMPTY_PERSISTED_STATE,
    activeSessionId,
    sessions: [session],
  });
}

describe('R2.1 single write session', () => {
  it('case 1: play → win → reload → state identical', async () => {
    const deps = createDeps();
    const session = minimalPlayingSession();
    await seedState(deps.driver, session);

    const preset = presets.find((p) => p.id === 'bingo-120');
    const draw = {
      ...baseDraw,
      dice: [1, 1, 2] as const,
      total: 4,
      flower: null,
      smallLarge: 'small' as const,
    };
    const outcome = applySettlementToSession(session, draw, preset);
    expect(outcome).not.toBeNull();
    if (outcome === null) {
      return;
    }
    expect(outcome.won).toBe(true);

    const winSession = createWinSessionUseCase({ sessions: deps.sessions });
    await winSession.execute(outcome.session);
    const reloaded = await deps.storage.load();

    expect(reloaded.activeSessionId).toBeNull();
    const saved = reloaded.sessions.find((s) => s.id === session.id);
    expect(saved?.status).toBe('won');
    expect(saved?.lastSettledDrawKey).toBe(draw.drawKey);
    expect(saved?.playedRounds).toHaveLength(1);
    expect(getCurrentPlan(saved!)?.status).toBe('won');
  });

  it('case 2: undo → reload → undo persisted', async () => {
    const deps = createDeps();
    const session = minimalPlayingSession();
    await seedState(deps.driver, session);

    const updateSession = createUpdateSessionUseCase({ sessions: deps.sessions });
    const afterBet = await updateSession.execute(session.id, (s) => {
      const updated = placeBetOnPlan(s, 1);
      if (updated === null) {
        throw new Error('expected bet to apply');
      }
      return updated;
    });
    expect(afterBet).not.toBeNull();

    const undoBet = createUndoBetUseCase({ sessions: deps.sessions });
    const undone = await undoBet.execute(session.id);
    expect(undone.ok).toBe(true);
    if (!undone.ok) {
      return;
    }

    const reloaded = await deps.storage.load();
    expect(reloaded).toEqual(undone.nextState);
    expect(getCurrentPlan(reloaded.sessions[0]!)?.completedThroughRound).toBe(0);
  });

  it('case 3: stop session → reload → state identical', async () => {
    const deps = createDeps();
    const session = minimalPlayingSession();
    await seedState(deps.driver, session);

    const stopSession = createStopSessionUseCase({ sessions: deps.sessions });
    const stopped = await stopSession.execute();
    expect(stopped.ok).toBe(true);
    if (!stopped.ok) {
      return;
    }

    const reloaded = await deps.storage.load();
    expect(reloaded).toEqual(stopped.nextState);
    expect(reloaded.activeSessionId).toBeNull();
    expect(reloaded.sessions[0]?.status).toBe('stopped');
  });

  it('case 4: session workflow persists only through SessionRepository', async () => {
    const deps = createDeps();
    const draft = draftSessionFromPlaying(minimalPlayingSession());
    await seedState(deps.driver, draft);

    const saveSpy = vi.spyOn(deps.storage, 'save');
    const startPlan = createStartPlanUseCase({ sessions: deps.sessions });
    const started = await startPlan.execute(draft.id);
    expect(started.ok).toBe(true);
    expect(saveSpy).toHaveBeenCalledTimes(1);

    saveSpy.mockClear();
    const playing = started.ok ? started.nextState.sessions[0]! : draft;
    const savePlaying = createSavePlayingSessionUseCase({ sessions: deps.sessions });
    await savePlaying.execute(startCurrentPlan(playing));
    expect(saveSpy).toHaveBeenCalledTimes(1);

    saveSpy.mockRestore();
  });
});

import { readFileSync } from 'node:fs';
import { join } from 'node:path';

import { describe, expect, it, vi } from 'vitest';

import {
  migratePersistedState,
  migratePersistedStateIdempotent,
  PERSISTED_STATE_VERSION,
  runPersistedStateMigration,
} from '@/services/storage/migrations';
import { MemoryStorageDriver } from '@/services/storage/MemoryStorageDriver';
import { PersistenceService } from '@/services/storage/PersistenceService';
import { APP_STATE_STORAGE_KEY } from '@/services/storage/repositories/app-state-repository';
import { LibraryRepository } from '@/services/storage/repositories/library-repository';
import { PlanCandidateRepository } from '@/services/storage/repositories/plan-candidate-repository';
import { PlanningDraftRepository } from '@/services/storage/repositories/planning-draft-repository';
import { RecommendationSetRepository } from '@/services/storage/repositories/recommendation-set-repository';
import { SessionRepository } from '@/services/storage/repositories/session-repository';

const FIXTURE_DIR = join(process.cwd(), 'tests', 'fixtures', 'persistence');

function loadFixture<T>(name: string): T {
  return JSON.parse(readFileSync(join(FIXTURE_DIR, name), 'utf8')) as T;
}

describe('R2.3 — Migration Evidence', () => {
  describe('Case 1: v5 → migrate → v6 parity', () => {
    it('preserves identical business state', () => {
      const v5 = loadFixture<unknown>('persisted-v5.json');
      const expected = loadFixture<unknown>('persisted-v6.expected.json');
      const { state, migratedFrom } = runPersistedStateMigration(v5);

      expect(migratedFrom).toBe(5);
      expect(state.version).toBe(PERSISTED_STATE_VERSION);
      expect(state).toEqual(expected);
    });
  });

  describe('Case 2: unknown optional field preserved', () => {
    it('keeps unrecognized fields through migration', () => {
      const raw = loadFixture<Record<string, unknown>>('persisted-v5-unknown-field.json');
      const migrated = migratePersistedState(raw);

      expect(migrated.version).toBe(PERSISTED_STATE_VERSION);
      expect(
        (migrated as unknown as Record<string, unknown>)['_maintainerExperimentalField'],
      ).toBe('preserve-me');
    });
  });

  describe('Case 3: old snapshot → repositories load', () => {
    it('upgrades legacy v2 and lets repositories read migrated state', async () => {
      const driver = new MemoryStorageDriver();
      await driver.put(APP_STATE_STORAGE_KEY, loadFixture('persisted-v2.json'));
      const storage = new PersistenceService(driver);

      const sessions = new SessionRepository(storage);
      const drafts = new PlanningDraftRepository(storage);
      const library = new LibraryRepository(storage);
      const candidates = new PlanCandidateRepository(storage);
      const recommendations = new RecommendationSetRepository(storage);

      const sessionState = await sessions.loadState();
      const draftState = await drafts.loadState();
      const libraryState = await library.loadState();
      const candidateState = await candidates.loadState();
      const recommendationState = await recommendations.loadState();

      expect(sessionState.version).toBe(PERSISTED_STATE_VERSION);
      expect(draftState.version).toBe(PERSISTED_STATE_VERSION);
      expect(libraryState.version).toBe(PERSISTED_STATE_VERSION);
      expect(candidateState.version).toBe(PERSISTED_STATE_VERSION);
      expect(recommendationState.version).toBe(PERSISTED_STATE_VERSION);

      expect(await drafts.get()).toBeNull();
      expect(await candidates.get()).toBeNull();
      expect(await recommendations.get()).toBeNull();
      expect(sessionState.sessions).toEqual([]);
      expect(libraryState.libraryCollections).toEqual([]);
      expect(sessionState.nextSessionNumber).toBe(3);
    });

    it('upgrades rich v5 snapshot for repository accessors', async () => {
      const driver = new MemoryStorageDriver();
      await driver.put(APP_STATE_STORAGE_KEY, loadFixture('persisted-v5.json'));
      const storage = new PersistenceService(driver);

      const sessions = new SessionRepository(storage);
      const drafts = new PlanningDraftRepository(storage);
      const library = new LibraryRepository(storage);

      const state = await sessions.loadState();
      expect(state.sessions).toHaveLength(1);
      expect(state.sessions[0]?.id).toBe('sess-fixture-001');
      expect(state.sessions[0]?.plans[0]?.marketId).toBe('total-4');

      const draft = await drafts.get();
      expect(draft?.draftId).toBe('draft-001');

      const libraryState = await library.loadState();
      expect(libraryState.libraryCollections).toHaveLength(1);
      expect(libraryState.capitalPlanner?.marketId).toBe('total-4');
    });
  });

  describe('Case 4: idempotent migration', () => {
    it('produces the same result when run twice', () => {
      const v5 = loadFixture<unknown>('persisted-v5.json');
      const once = migratePersistedState(v5);
      const twice = migratePersistedStateIdempotent(v5);

      expect(twice).toEqual(once);
      expect(migratePersistedState(once)).toEqual(once);
    });

    it('does not report migration when source is already current', () => {
      const v6 = migratePersistedState(loadFixture('persisted-v5.json'));
      const { migratedFrom } = runPersistedStateMigration(v6);

      expect(migratedFrom).toBeNull();
    });
  });

  describe('Regression matrix: legacy versions → current', () => {
    it.each([
      ['persisted-v2.json', 2],
      ['persisted-v5.json', 5],
    ] as const)('migrates %s forward-only to v%s', (fixture, fromVersion) => {
      const raw = loadFixture<unknown>(fixture);
      const { state, migratedFrom } = runPersistedStateMigration(raw);

      expect(migratedFrom).toBe(fromVersion);
      expect(state.version).toBe(PERSISTED_STATE_VERSION);
    });

    it('migrates v2 active/history shape with stable plan ids when UUID is fixed', () => {
      const uuid = vi
        .spyOn(crypto, 'randomUUID')
        .mockReturnValue('00000000-0000-4000-8000-000000000001');

      const v2 = {
        version: 2,
        theme: 'light',
        nextSessionNumber: 1,
        activePresetId: 'bingo-120',
        customGamePresets: [],
        activeSession: {
          id: 'active-legacy-001',
          sessionNumber: 1,
          status: 'ready',
          formValues: {
            targetProfit: '100.000',
            roundCount: '5',
            rewardMultiplier: '20',
            minimumBet: '10.000',
            maximumBet: '1.000.000',
            betStep: '10.000',
            userBankroll: '30.000.000',
            winTaxEnabled: true,
            winTaxThreshold: '10.000.000',
            winTaxRatePercent: '10',
          },
          generated: loadFixture<{ planningDraft: { generated: unknown } }>(
            'persisted-v5.json',
          ).planningDraft.generated,
          completedThroughRound: 0,
          timeline: [],
          createdAt: '2026-01-01T00:00:00.000Z',
          updatedAt: '2026-01-01T00:00:00.000Z',
        },
        history: [],
      };

      const migrated = migratePersistedState(v2);
      uuid.mockRestore();

      expect(migrated.version).toBe(PERSISTED_STATE_VERSION);
      expect(migrated.sessions).toHaveLength(1);
      expect(migrated.sessions[0]?.id).toBe('active-legacy-001');
      expect(migrated.sessions[0]?.plans[0]?.id).toBe('00000000-0000-4000-8000-000000000001');
      expect(migrated.activeSessionId).toBe('active-legacy-001');
    });
  });
});

import { describe, expect, it, vi, afterEach } from 'vitest';

import { FakeClock } from '@/services/clock/fake-clock';
import { EventBus } from '@/services/events/domain-events';
import { EMPTY_PERSISTED_STATE } from '@/features/session/session-types';
import { PersistenceHealthMonitor } from '@/services/storage/persistence-health';
import { buildPersistenceSnapshot } from '@/services/storage/persistence-snapshot';
import { MemoryStorageDriver } from '@/services/storage/MemoryStorageDriver';
import { PersistenceService } from '@/services/storage/PersistenceService';
import { APP_STATE_STORAGE_KEY } from '@/services/storage/repositories/app-state-repository';
import { classifyStorageErrorMessage, formatStorageErrorCause } from '@/services/storage/storage-errors';
import { refreshPersistenceCapability } from '@/product-shell/ui/diagnostics/persistence-capability';
import {
  createAppServices,
  resetAppServicesForTests,
} from '@/services/registry/app-services';
import { IndexedDbDriver } from '@/services/storage/IndexedDbDriver';
import { createDiagnosticCapabilities } from '@/product-shell/ui/diagnostics/create-capabilities';
import { createAppDiagnosticsPorts } from '@/app/diagnostics-ports';

describe('R2.4 — Persistence Observability', () => {
  afterEach(() => {
    resetAppServicesForTests();
    vi.restoreAllMocks();
  });

  describe('storage-errors taxonomy', () => {
    it('maps known failure messages to operator-facing causes', () => {
      expect(classifyStorageErrorMessage('IndexedDB open failed')).toBe('storage_open_failed');
      expect(classifyStorageErrorMessage('migration failed: corrupt payload')).toBe(
        'migration_failed',
      );
      expect(classifyStorageErrorMessage('QuotaExceededError')).toBe('quota_exceeded');
      expect(formatStorageErrorCause('indexeddb_unavailable')).toBe('IndexedDB Unavailable');
    });
  });

  describe('Case 1: IndexedDB unavailable → Offline', () => {
    it('reports offline when IndexedDB probe fails', async () => {
      vi.stubGlobal('indexedDB', undefined);

      const health = new PersistenceHealthMonitor(
        new EventBus(new FakeClock(new Date('2026-06-30T00:00:00.000Z'))),
        new FakeClock(new Date('2026-06-30T00:00:00.000Z')),
      );
      const snapshot = await buildPersistenceSnapshot({
        driver: new IndexedDbDriver(),
        health: health.getView(),
        checkedAt: '2026-06-30T00:00:00.000Z',
      });

      expect(snapshot.status).toBe('offline');
      expect(snapshot.driverLabel).toBe('IndexedDB');
      health.dispose();
      vi.unstubAllGlobals();
    });
  });

  describe('Case 2: migration failed → Critical', () => {
    it('surfaces migration failure in health and diagnostic snapshot', async () => {
      const clock = new FakeClock(new Date('2026-06-30T00:00:00.000Z'));
      const bus = new EventBus(clock);
      const health = new PersistenceHealthMonitor(bus, clock);

      bus.emit(bus.createEvent('StorageFailed', { reason: 'migration failed: invalid version' }));

      const view = health.getView();
      expect(view.status).toBe('critical');
      expect(view.lastMigration?.status).toBe('failed');
      expect(view.lastError?.cause).toBe('migration_failed');

      const diagnostic = await buildPersistenceSnapshot({
        driver: new MemoryStorageDriver(),
        health: view,
        checkedAt: '2026-06-30T00:00:00.000Z',
      });
      expect(diagnostic.status).toBe('critical');
      health.dispose();
    });
  });

  describe('Case 3: successful save updates Last Save', () => {
    it('records StorageSaved on persistence service save', async () => {
      const clock = new FakeClock(new Date('2026-06-30T12:00:00.000Z'));
      const bus = new EventBus(clock);
      const health = new PersistenceHealthMonitor(bus, clock);
      const storage = new PersistenceService(new MemoryStorageDriver(), bus);

      await storage.save({ ...EMPTY_PERSISTED_STATE, nextSessionNumber: 9 });

      expect(health.getView().lastSaveAt).toBe('2026-06-30T12:00:00.000Z');
      health.dispose();
    });
  });

  describe('Case 4: Diagnostics refresh', () => {
    it('refreshes persistence capability through diagnostics ports', async () => {
      const services = createAppServices({
        storageDriver: new MemoryStorageDriver(),
        clock: new FakeClock(new Date('2026-06-30T00:00:00.000Z')),
      });
      resetAppServicesForTests(services);

      const driver = services.storageDriver as MemoryStorageDriver;
      await driver.put(APP_STATE_STORAGE_KEY, {
        ...EMPTY_PERSISTED_STATE,
        nextSessionNumber: 4,
      });
      await services.storage.load();
      await services.storage.save({ ...EMPTY_PERSISTED_STATE, nextSessionNumber: 5 });

      const capabilities = createDiagnosticCapabilities(
        createAppDiagnosticsPorts({
          fetchCollectorHealth: async () => null,
          notificationCount: 0,
          unreadNotificationCount: 0,
          statisticsError: null,
          statisticsLoading: false,
          statisticsDrawCount: null,
          cloudEnabled: false,
          buildVersion: 'test',
          runtimeHealthy: true,
        }),
      );

      const storageCapability = capabilities.find((entry) => entry.id === 'storage');
      expect(storageCapability).toBeDefined();

      const snapshot = await storageCapability!.refresh();
      expect(snapshot.rows.some((row) => row.label === 'Schema Version' && row.value === '6')).toBe(
        true,
      );
      expect(snapshot.rows.some((row) => row.label === 'Last Save' && row.value !== '—')).toBe(
        true,
      );
      expect(snapshot.summary).toContain('schema v6');

      services.telemetry.dispose();
      services.logger.dispose();
      services.health.dispose();
      services.persistenceHealth.dispose();
    });

    it('refreshPersistenceCapability returns structured rows without repository imports in UI layer', async () => {
      const services = createAppServices({ storageDriver: new MemoryStorageDriver() });
      resetAppServicesForTests(services);

      const snapshot = await refreshPersistenceCapability(services);
      expect(snapshot.rows.map((row) => row.label)).toEqual([
        'Status',
        'Storage Driver',
        'Schema Version',
        'Last Migration',
        'Last Save',
        'Last Load',
        'Last Error',
        'Sessions',
        'Drafts',
        'Candidates',
        'Library Collections',
        'Notifications',
        'Storage Size',
      ]);

      services.telemetry.dispose();
      services.logger.dispose();
      services.health.dispose();
      services.persistenceHealth.dispose();
    });
  });
});
